			...data,
			sizes: this.parseJsonField(data.sizes),
			default_unit_prices: this.parseJsonField(data.default_unit_prices),
			colors: this.parseJsonField(data.colors),
			brand: this.parseJsonField(data.brand),
			condensed_features: this.parseJsonField(data.condensed_features),
			broad_category_names: this.parseJsonField(data.broad_category_names),
			sub_category_names: this.parseJsonField(data.sub_category_names),
			no_minimum: Boolean(data.no_minimum),
		};
	}

	private parseJsonField<T>(field: T | string | null): T | null {
		if (field === null || field === undefined) {
			return null;
		}
